"use client";

// Import Next
import Image from "next/image";
// Import React
import { useState, useEffect } from "react";
// Import Lucide Icons
import { Star, ChevronLeft, ChevronRight, Quote } from "lucide-react";
// Import Framer Motion
import { motion, AnimatePresence } from "framer-motion";
// Import datas
import { testimonials } from "@/data/testimonials";

// Composant TestimonialsSection de la page d'accueil
export default function TestimonialsSection() {
    const [currentIndex, setCurrentIndex] = useState(0);

    const nextReview = () => {
        setCurrentIndex((prev) => (prev + 1) % testimonials.length);
    };

    const prevReview = () => {
        setCurrentIndex((prev) => (prev - 1 + testimonials.length) % testimonials.length);
    };

    useEffect(() => {
        const timer = setInterval(nextReview, 8000);
        return () => clearInterval(timer);
    }, []);

    return (
        <section className="py-24 md:py-32 bg-[#FDFBF7] relative overflow-hidden w-full">
            <div className="mx-auto px-0 xl:px-20 text-center relative z-10">

                {/* Titres */}
                <div className="text-center mb-16 space-y-4">
                    {/* Titre */}
                    <h2 className="font-cormorant text-6xl md:text-7xl text-gray-900 font-light italic">
                        Ils m'ont fait confiance
                    </h2>
                    {/* Sous-titre */}
                    <p className="text-gray-500 italic">
                        Découvrez ce que disent mes clients
                    </p>
                    <div className="w-24 h-1 bg-black mx-auto mt-6"></div>
                </div>

                {/* Avatar et étoiles */}
                <div className="flex flex-col items-center w-full mb-8">
                    {/* Avatar */}
                    <div className="relative w-24 h-24 md:w-32 md:h-32 rounded-full overflow-hidden mb-6 border-4 border-white shadow-lg">
                        <Image
                            src={testimonials[currentIndex].image}
                            alt={testimonials[currentIndex].name}
                            fill
                            sizes="(max-width: 768px) 96px, 128px"
                            className="object-cover"
                        />
                    </div>
                    {/* Étoiles */}
                    <div className="flex gap-1">
                        {[...Array(5)].map((_, i) => (
                            <Star key={i} className="w-4 h-4 text-terra fill-terra" />
                        ))}
                    </div>
                </div>

                {/* Slider de texte avec flèches */}
                <div className="relative w-full flex items-center justify-center">

                    {/* Précédent */}
                    <button
                        onClick={prevReview}
                        className="absolute left-0 p-2 text-terra/30 hover:text-terra transition-colors z-20"
                        aria-label="Précédent"
                    >
                        <ChevronLeft size={48} strokeWidth={1} />
                    </button>

                    {/* Texte animé */}
                    <div className="w-full min-h-[250px] md:min-h-[200px] flex items-center justify-center">
                        <AnimatePresence mode="popLayout">
                            <motion.div
                                key={currentIndex}
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, y: -10 }}
                                transition={{ duration: 0.5 }}
                                className="relative w-full"
                            >
                                <Quote className="absolute -top-10 left-4 md:left-10 w-10 h-10 text-terra/10 fill-current" />
                                <h2 className="font-cormorant text-2xl md:text-4xl leading-relaxed text-gray-800 italic font-light px-12 md:px-24">
                                    &quot;{testimonials[currentIndex].text}&quot;
                                </h2>
                                <Quote className="absolute -bottom-10 right-4 md:right-10 w-10 h-10 text-terra/10 fill-current rotate-180" />
                            </motion.div>
                        </AnimatePresence>
                    </div>

                    {/* Suivant */}
                    <button
                        onClick={nextReview}
                        className="absolute right-0 p-2 text-terra/30 hover:text-terra transition-colors z-20"
                        aria-label="Suivant"
                    >
                        <ChevronRight size={48} strokeWidth={1} />
                    </button>
                </div>

                {/* Auteur et indicateurs */}
                <div className="mt-8 space-y-6">
                    <div className="space-y-1">
                        {/* Auteur */}
                        <p className="text-base font-bold text-gray-900 uppercase tracking-widest">
                            {testimonials[currentIndex].name}
                        </p>
                        {/* Rôle */}
                        <p className="text-xs text-terra font-medium uppercase tracking-wider">
                            {testimonials[currentIndex].role}
                        </p>
                    </div>

                    {/* Indicateurs */}
                    <div className="flex justify-center gap-3">
                        {testimonials.map((_, index) => (
                            <button
                                key={index}
                                onClick={() => setCurrentIndex(index)}
                                aria-label={`Voir le témoignage de ${testimonials[index].name}`}
                                className={`w-2 h-2 rounded-full transition-all duration-300 ${
                                    index === currentIndex ? "bg-terra w-6" : "bg-terra/20 hover:bg-terra/40"
                                }`}
                            />
                        ))}
                    </div>
                </div>
            </div>
        </section>
    );
}

"use client";

// Import React
import { useState } from "react";
import Link from "next/link";
import { Send } from "lucide-react";
import FloatingInput from "./FloatingInput";

interface ContactFormProps {
    title?: string;
    subtitle?: string;
    className?: string;
}

export default function ContactForm({ 
    title = "Envoyer un message", 
    subtitle = "Je vous répondrai dans les plus brefs délais.",
    className = "" 
}: ContactFormProps) {
    const [messageLength, setMessageLength] = useState(0);
    const [status, setStatus] = useState<"idle" | "loading" | "success" | "error">("idle");

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setStatus("loading");

        const formData = new FormData(e.currentTarget);
        const data = Object.fromEntries(formData.entries());

        try {
            const response = await fetch("/api/contact", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(data),
            });

            if (response.ok) {
                setStatus("success");
                (e.target as HTMLFormElement).reset();
                setMessageLength(0);
            } else {
                setStatus("error");
            }
        } catch (err) {
            setStatus("error");
        }
    };

    if (status === "success") {
        return (
            <div className={`bg-white p-8 md:p-12 rounded-xl shadow-2xl text-center space-y-6 ${className}`}>
                <div className="w-20 h-20 bg-green-50 text-green-500 rounded-full flex items-center justify-center mx-auto mb-6">
                    <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" />
                    </svg>
                </div>
                <h3 className="font-cormorant text-4xl text-gray-900 italic">Merci pour votre message !</h3>
                <p className="text-gray-500 font-light">Je reviendrai vers vous très prochainement.</p>
                <button 
                    onClick={() => setStatus("idle")}
                    className="mt-8 text-terra font-bold uppercase tracking-widest text-xs hover:underline"
                >
                    Envoyer un autre message
                </button>
            </div>
        );
    }

    return (
        <div className={`bg-white p-8 md:p-12 rounded-xl shadow-2xl ${className}`}>
            <form onSubmit={handleSubmit} className="space-y-10">

                {/* Titres */}
                <div className="mb-10 text-center lg:text-left">
                    <h3 className="font-cormorant text-4xl text-gray-900 italic mb-2">{title}</h3>
                    {subtitle && <p className="text-gray-500 font-light text-sm">{subtitle}</p>}
                </div>

                {/* Nom complet / Téléphone */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                    <FloatingInput id="name" label="Nom complet" type="text" required />
                    <FloatingInput 
                        id="phone" 
                        label="Téléphone" 
                        type="tel" 
                        required
                        pattern="^(0|\\+33|\\+32)[1-9][0-9]{7,12}$" 
                    />
                </div>

                {/* Email */}
                <FloatingInput id="email" label="Adresse Email" type="email" required />

                {/* Sujet et Date*/}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                    <div className="relative z-0 w-full group">
                        <select 
                            id="subject" 
                            name="subject" 
                            required 
                            defaultValue=""
                            className="block py-3 px-0 w-full text-base text-gray-900 bg-transparent border-0 border-b border-gray-300 appearance-none focus:outline-none focus:ring-0 focus:border-terra peer"
                        >
                            <option value="" disabled>Choisir...</option>
                            <option value="commande">Commande sur mesure</option>
                            <option value="achat">Achat d&apos;œuvre</option>
                            <option value="exposition">Proposition d&apos;exposition</option>
                            <option value="autre">Autre</option>
                        </select>
                        <label htmlFor="subject" className="peer-focus:font-medium absolute text-lg text-gray-500 font-cormorant italic duration-300 transform -translate-y-6 scale-75 top-3 -z-10 origin-[0] peer-focus:left-0 peer-focus:text-terra peer-placeholder-shown:scale-100 peer-placeholder-shown:translate-y-0 peer-focus:scale-75 peer-focus:-translate-y-6">
                            Sujet de la demande
                        </label>
                    </div>
                    <FloatingInput id="date" label="Date souhaitée (optionnel)" type="date" />
                </div>

                {/* Message */}
                <div className="relative">
                    <FloatingInput 
                        id="message" 
                        label="Votre message..." 
                        isTextArea 
                        required 
                        maxLength={500}
                        onChange={(e) => setMessageLength((e.target as HTMLTextAreaElement).value.length)}
                    />
                    <div className={`text-[10px] text-right mt-1 uppercase tracking-widest ${messageLength >= 500 ? 'text-red-500 font-bold' : 'text-gray-400'}`}>
                        {messageLength} / 500
                    </div>
                </div>

                {/* Checkbox */}
                <div className="flex items-start gap-3 py-2">
                    <input type="checkbox" id="accept" required className="mt-1 accent-terra w-4 h-4 cursor-pointer" />
                    <label htmlFor="accept" className="text-xs text-gray-500 leading-relaxed cursor-pointer text-left">
                        Je consens à ce que mes données soient traitées pour répondre à ma demande, conformément à la <Link href="/politique" className="underline hover:text-terra">politique de confidentialité</Link>.
                    </label>
                </div>

                {/* État d&apos;erreur */}
                {status === "error" && (
                    <div className="text-red-500 text-sm text-center">
                        Une erreur est survenue lors de l&apos;envoi. Veuillez réessayer.
                    </div>
                )}

                {/* Bouton envoyer le message */}
                <button
                    type="submit"
                    disabled={status === "loading"}
                    className="w-full bg-black text-white py-4 flex items-center justify-center gap-3 hover:bg-terra transition-all duration-500 group uppercase tracking-[0.2em] text-xs font-bold shadow-lg hover:shadow-xl disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    {status === "loading" ? "Envoi en cours..." : "Envoyer le message"}
                    {status !== "loading" && <Send size={16} className="group-hover:translate-x-2 group-hover:-translate-y-1 transition-transform duration-500" />}
                </button>
            </form>
        </div>
    );
}

"use client";

import { useState, FormEvent } from "react";
import { BiSend } from "react-icons/bi";
import type { NewsletterResponse } from "@/types/newsletter";

type FormStatus = "idle" | "loading" | "success" | "error";

export default function NewsletterForm() {
  const [email, setEmail] = useState("");
  const [status, setStatus] = useState<FormStatus>("idle");
  const [message, setMessage] = useState("");

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();

    // Validation côté client
    if (!email || !email.includes("@")) {
      setStatus("error");
      setMessage("Veuillez entrer une adresse email valide");
      return;
    }

    setStatus("loading");
    setMessage("");

    try {
      const response = await fetch("/api/newsletter", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ email }),
      });

      const data: NewsletterResponse = await response.json();

      if (response.ok) {
        setStatus("success");
        setMessage(data.message || "Inscription réussie !");
        setEmail(""); // Réinitialiser le champ
      } else {
        setStatus("error");
        setMessage(data.error || "Une erreur est survenue");
      }
    } catch (err) {
      setStatus("error");
      setMessage("Erreur de connexion. Veuillez réessayer.");
    }
  };

  return (
    <div>
      <form onSubmit={handleSubmit} className="flex mb-2">
        <input
          type="email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          placeholder="Votre email"
          disabled={status === "loading" || status === "success"}
          className="flex-1 bg-white text-black px-4 py-2 rounded-l-sm focus:outline-none disabled:opacity-50 disabled:cursor-not-allowed"
          required
        />
        <button
          type="submit"
          disabled={status === "loading" || status === "success"}
          className="bg-gray-800 px-4 py-2 rounded-r-sm hover:bg-terra transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
          aria-label="S'inscrire"
        >
          {status === "loading" ? (
            <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
          ) : (
            <BiSend size={20} />
          )}
        </button>
      </form>

      {/* Messages de statut */}
      {message && (
        <p
          className={`text-sm mt-2 ${
            status === "success"
              ? "text-green-400"
              : status === "error"
              ? "text-red-400"
              : "text-gray-400"
          }`}
        >
          {message}
        </p>
      )}
    </div>
  );
}
